// NEXAI Voice · Rückruf-Wunsch — Payload lesen (flach ODER Vapi-Envelope)
const TZ = 'Europe/Berlin';

const root = $input.first().json || {};
const body = (root.body && typeof root.body === 'object') ? root.body : root;
let toolCallId = '';
let a = {};
if (body && body.message && Array.isArray(body.message.toolCalls) && body.message.toolCalls[0]) {
  const tc = body.message.toolCalls[0];
  toolCallId = tc.id || '';
  let ar = tc.function && tc.function.arguments;
  if (typeof ar === 'string') { try { ar = JSON.parse(ar); } catch (e) { ar = {}; } }
  a = ar || {};
} else {
  a = body || {};
  toolCallId = body.toolCallId || '';
}

// Anrufernummer aus dem Vapi-Envelope — nur bei echten Telefonanrufen gesetzt, bei Web-Calls leer
let callerNumber = '';
try { callerNumber = String(body.message.call.customer.number || '').trim(); } catch (e) { callerNumber = ''; }

const name = String(a.name != null ? a.name : '').trim();
const email = String(a.email != null ? a.email : '').trim();
const telefon = String((a.telefon != null ? a.telefon : a.phone) || '').trim();
const anliegen = String((a.anliegen != null ? a.anliegen : a.topic) || '').trim();
const dringlichkeit = String((a.dringlichkeit != null ? a.dringlichkeit : a.urgency) || '').trim();

// Rückrufnummer: was der Anrufer nennt, sonst die Nummer, von der er anruft
const rueckrufnummer = telefon || callerNumber;
const valid = Boolean(rueckrufnummer || email);

const eingegangen = $now.setZone(TZ).toFormat('dd.LL.yyyy HH:mm');

return [{ json: { valid, toolCallId, name, email, telefon, callerNumber, rueckrufnummer, anliegen, dringlichkeit, eingegangen } }];

const p = $('Parse & Normalize').first().json;
const wohin = p.rueckrufnummer ? ('unter ' + p.rueckrufnummer) : ('per E-Mail an ' + p.email);
const result = 'Der Rückrufwunsch ist notiert und das Team wurde benachrichtigt. Bestätige dem Anrufer kurz, dass sich ein Kollege zeitnah ' + wohin + ' meldet, und verabschiede dich freundlich.';
return [{ json: { results: [{ toolCallId: p.toolCallId, result }] } }];

const p = $('Parse & Normalize').first().json;
const result = 'Es fehlt noch ein Weg, den Anrufer zu erreichen. Frag freundlich nach der Telefonnummer, unter der wir zurückrufen dürfen.';
return [{ json: { results: [{ toolCallId: p.toolCallId, result }] } }];
